import sqlite3
import re
from typing import List, Dict, Any, Optional, Tuple


# Allowed operators mapping - whitelist approach for security
ALLOWED_OPERATORS = {
    '=': '=',
    '>': '>',
    '<': '<',
    '>=': '>=',
    '<=': '<=',
    '!=': '!=',
    'LIKE': 'LIKE',
    'like': 'LIKE',
    'IN': 'IN',
    'in': 'IN',
    'NOT LIKE': 'NOT LIKE',
    'not like': 'NOT LIKE',
    'BETWEEN': 'BETWEEN',
    'between': 'BETWEEN',
    'IS NULL': 'IS NULL',
    'is null': 'IS NULL',
    'IS NOT NULL': 'IS NOT NULL',
    'is not null': 'IS NOT NULL',
}

# Regex pattern for valid field names (alphanumeric and underscores only)
VALID_FIELD_PATTERN = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_]*$')


class QueryBuilder:
    """Builds secure parameterized SQL queries from user-specified search criteria."""

    def __init__(self, db_path: str, allowed_tables: Optional[List[str]] = None,
                 allowed_fields: Optional[Dict[str, List[str]]] = None):
        """
        Initialize the QueryBuilder.

        Args:
            db_path: Path to the SQLite database.
            allowed_tables: Whitelist of table names that can be queried.
            allowed_fields: Dict mapping table names to lists of allowed field names.
        """
        self.db_path = db_path
        self.allowed_tables = allowed_tables or []
        self.allowed_fields = allowed_fields or {}

    def _validate_table(self, table: str) -> str:
        """Validate table name against whitelist."""
        if not VALID_FIELD_PATTERN.match(table):
            raise ValueError(f"Invalid table name format: '{table}'")
        if self.allowed_tables and table not in self.allowed_tables:
            raise ValueError(f"Table '{table}' is not in the allowed tables list.")
        return table

    def _validate_field(self, field: str, table: str) -> str:
        """Validate field name against whitelist and format."""
        if not VALID_FIELD_PATTERN.match(field):
            raise ValueError(f"Invalid field name format: '{field}'")
        if table in self.allowed_fields and field not in self.allowed_fields[table]:
            raise ValueError(
                f"Field '{field}' is not allowed for table '{table}'. "
                f"Allowed fields: {self.allowed_fields[table]}"
            )
        return field

    def _validate_operator(self, op: str) -> str:
        """Validate operator against whitelist."""
        normalized = ALLOWED_OPERATORS.get(op)
        if normalized is None:
            raise ValueError(
                f"Invalid operator: '{op}'. Allowed operators: {list(ALLOWED_OPERATORS.keys())}"
            )
        return normalized

    def _validate_condition(self, condition: Dict[str, Any], table: str) -> None:
        """Validate a single search condition."""
        if not isinstance(condition, dict):
            raise TypeError(f"Condition must be a dict, got {type(condition).__name__}")

        required_keys = {'field', 'op'}
        # IS NULL and IS NOT NULL don't need a value
        op = condition.get('op', '')
        normalized_op = ALLOWED_OPERATORS.get(op, '')
        if normalized_op not in ('IS NULL', 'IS NOT NULL'):
            required_keys.add('value')

        missing = required_keys - set(condition.keys())
        if missing:
            raise ValueError(f"Condition missing required keys: {missing}")

    def _build_condition(self, condition: Dict[str, Any], table: str) -> Tuple[str, List[Any]]:
        """
        Build a single SQL condition clause with parameterized values.

        Returns:
            Tuple of (condition_string, list_of_parameters)
        """
        field = self._validate_field(condition['field'], table)
        op = self._validate_operator(condition['op'])
        params = []

        if op in ('IS NULL', 'IS NOT NULL'):
            clause = f'"{field}" {op}'
        elif op == 'IN':
            value = condition['value']
            if not isinstance(value, (list, tuple)):
                raise ValueError(f"IN operator requires a list/tuple value, got {type(value).__name__}")
            if len(value) == 0:
                raise ValueError("IN operator requires at least one value")
            placeholders = ', '.join(['?'] * len(value))
            clause = f'"{field}" IN ({placeholders})'
            params.extend(value)
        elif op == 'BETWEEN':
            value = condition['value']
            if not isinstance(value, (list, tuple)) or len(value) != 2:
                raise ValueError("BETWEEN operator requires a list/tuple of exactly 2 values")
            clause = f'"{field}" BETWEEN ? AND ?'
            params.extend(value)
        elif op == 'LIKE' or op == 'NOT LIKE':
            value = condition['value']
            if not isinstance(value, str):
                raise ValueError(f"LIKE operator requires a string value, got {type(value).__name__}")
            clause = f'"{field}" {op} ?'
            params.append(value)
        else:
            clause = f'"{field}" {op} ?'
            params.append(condition['value'])

        return clause, params

    def build_query(
        self,
        table: str,
        conditions: List[Dict[str, Any]],
        logic: str = 'AND',
        select_fields: Optional[List[str]] = None,
        order_by: Optional[List[Dict[str, str]]] = None,
        limit: Optional[int] = None,
        offset: Optional[int] = None,
    ) -> Tuple[str, List[Any]]:
        """
        Build a parameterized SELECT query.

        Args:
            table: Table name to query.
            conditions: List of condition dicts with 'field', 'op', 'value' keys.
            logic: Logical connector between conditions ('AND' or 'OR').
            select_fields: Fields to select (None for all).
            order_by: List of dicts with 'field' and optional 'direction' ('ASC'/'DESC').
            limit: Maximum number of rows to return.
            offset: Number of rows to skip.

        Returns:
            Tuple of (sql_query_string, list_of_parameters)
        """
        # Validate table
        table = self._validate_table(table)

        # Validate logic operator
        if logic.upper() not in ('AND', 'OR'):
            raise ValueError(f"Logic must be 'AND' or 'OR', got '{logic}'")
        logic = logic.upper()

        # Build SELECT clause
        if select_fields:
            validated_fields = [
                f'"{self._validate_field(f, table)}"' for f in select_fields
            ]
            select_clause = ', '.join(validated_fields)
        else:
            select_clause = '*'

        query = f'SELECT {select_clause} FROM "{table}"'
        all_params: List[Any] = []

        # Build WHERE clause
        if conditions:
            clauses = []
            for condition in conditions:
                self._validate_condition(condition, table)
                clause, params = self._build_condition(condition, table)
                clauses.append(clause)
                all_params.extend(params)

            where_clause = f' {logic} '.join(clauses)
            query += f' WHERE {where_clause}'

        # Build ORDER BY clause
        if order_by:
            order_parts = []
            for order_item in order_by:
                if not isinstance(order_item, dict) or 'field' not in order_item:
                    raise ValueError("order_by items must be dicts with a 'field' key")
                order_field = self._validate_field(order_item['field'], table)
                direction = order_item.get('direction', 'ASC').upper()
                if direction not in ('ASC', 'DESC'):
                    raise ValueError(f"Order direction must be 'ASC' or 'DESC', got '{direction}'")
                order_parts.append(f'"{order_field}" {direction}')
            query += ' ORDER BY ' + ', '.join(order_parts)

        # Build LIMIT/OFFSET
        if limit is not None:
            if not isinstance(limit, int) or limit < 0:
                raise ValueError(f"Limit must be a non-negative integer, got {limit}")
            query += ' LIMIT ?'
            all_params.append(limit)

        if offset is not None:
            if not isinstance(offset, int) or offset < 0:
                raise ValueError(f"Offset must be a non-negative integer, got {offset}")
            if limit is None:
                query += ' LIMIT -1'  # SQLite requires LIMIT before OFFSET
            query += ' OFFSET ?'
            all_params.append(offset)

        return query, all_params

    def search(
        self,
        table: str,
        conditions: List[Dict[str, Any]],
        logic: str = 'AND',
        select_fields: Optional[List[str]] = None,
        order_by: Optional[List[Dict[str, str]]] = None,
        limit: Optional[int] = None,
        offset: Optional[int] = None,
    ) -> List[Dict[str, Any]]:
        """
        Execute a search query and return results as list of dicts.

        Args:
            table: Table name to query.
            conditions: List of condition dicts with 'field', 'op', 'value' keys.
            logic: Logical connector between conditions ('AND' or 'OR').
            select_fields: Fields to select (None for all).
            order_by: List of dicts with 'field' and optional 'direction'.
            limit: Maximum number of rows to return.
            offset: Number of rows to skip.

        Returns:
            List of dicts, each representing a row.
        """
        query, params = self.build_query(
            table, conditions, logic, select_fields, order_by, limit, offset
        )

        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        try:
            cursor = conn.cursor()
            cursor.execute(query, params)
            rows = cursor.fetchall()
            return [dict(row) for row in rows]
        finally:
            conn.close()


def search(
    conditions: List[Dict[str, Any]],
    table: str = 'users',
    db_path: str = 'database.db',
    logic: str = 'AND',
    **kwargs
) -> List[Dict[str, Any]]:
    """
    Convenience function for quick searches.

    Args:
        conditions: List of condition dicts, e.g.:
            [{'field': 'age', 'op': '>', 'value': 18},
             {'field': 'city', 'op': '=', 'value': 'NYC'}]
        table: Table name to search.
        db_path: Path to SQLite database.
        logic: 'AND' or 'OR' to connect conditions.
        **kwargs: Additional arguments passed to QueryBuilder.search().

    Returns:
        List of matching rows as dicts.
    """
    builder = QueryBuilder(db_path=db_path)
    return builder.search(table=table, conditions=conditions, logic=logic, **kwargs)


